259→    fn make_analysis(name: &str, exported: bool, branch_count: usize) -> FunctionAnalysis {
260→        FunctionAnalysis {
261→            name: name.to_string(),
262→            exported,
263→            params: vec![ParamInfo {
264→                name: "x".into(),
265→                typ: TypeInfo::Int,
266→                type_name: None,
267→            }],
268→            branches: (0..branch_count)
269→                .map(|i| BranchInfo {
270→                    id: i as u32,
271→                    line: (i + 1) as u32,
272→                    condition_text: format!("cond_{i}"),
273→                    condition: None,
274→                    branch_type: BranchType::If,
275→                })
276→                .collect(),
277→            dependencies: vec![],
278→            return_type: TypeInfo::Int,
279→            start_line: 1,
280→            end_line: 10,
281→            literals: vec![],
282→            crypto_boundaries: vec![],
283→        }
284→    }
285→
286→    fn make_analysis_with_deps(
287→        name: &str,
288→        exported: bool,
289→        deps: Vec<&str>,
290→    ) -> FunctionAnalysis {
291→        let mut a = make_analysis(name, exported, 0);
292→        a.dependencies = deps
293→            .into_iter()
294→            .map(|d| ExternalDependency {
295→                kind: DependencyKind::FunctionCall,
296→                symbol: d.to_string(),
297→                source_module: String::new(),
298→                return_type: TypeInfo::Unknown,
299→                param_types: vec![],
300→                call_sites: vec![],
301→            })
302→            .collect();
303→        a
304→    }
