591→    fn noop_config() -> crate::frontend::FrontendConfig {
592→        let mut config = crate::frontend::FrontendConfig::new(PathBuf::from("bash"));
593→        config.args = vec![noop_frontend_path().to_string_lossy().into_owned()];
594→        config.request_timeout = std::time::Duration::from_secs(5);
595→        config
