598→    #[tokio::test]
599→    async fn batch_analyze_with_noop_frontend() {
600→        let config = noop_config();
601→        let frontend = Frontend::spawn(&config).await.expect("spawn failed");
602→
603→        let mut frontends = HashMap::new();
604→        frontends.insert(Language::TypeScript, frontend);
605→
606→        let files = vec![
607→            (PathBuf::from("src/app.ts"), Language::TypeScript),
608→            (PathBuf::from("src/utils.ts"), Language::TypeScript),
609→        ];
610→
611→        let registry = batch_analyze(&mut frontends, &files, None, None)
612→            .await
613→            .expect("batch analyze failed");
614→
615→        // Noop frontend returns one "stub" function per file
616→        assert_eq!(registry.len(), 2);
617→        assert_eq!(
